# Calculate number of correct licks for a given session
import re
def get_correct_licks(nwb):
    lick_times = nwb.acquisition['licks'].timestamps
    img_time = nwb.intervals['behavior_presentations']['start_time']
    img_stop = img_time[-1]+.5
    img_time = np.append(img_time,img_stop)
    img_names = nwb.intervals['behavior_presentations']['image_name']
    img_fams = []
    for name in img_names:
        img_fams.append(int(re.findall(r'\d+', name)[0]))
    trans = [False]
    licks = []
    for i in range(1, len(img_fams)):
        if img_fams[i-1] == img_fams[i]:
            trans.append(False)
        else:
            trans.append(True)
    for i in range(1, len(img_time)):
        licks.append(any([img_time[i-1] < x < img_time[i] for x in lick_times]))
    true_pos = []
    for i in range(0, len(trans)):
        if trans[i] == True:
            true_pos.append(licks[i])
    return true_pos
